GameTeam = class("GameTeam")

function GameTeam:ctor(userId)
    self.captainUserId = tostring(userId)
    self.teamMember = {}
    self:onCreate()
end

function GameTeam:onCreate()
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        GamePacketSender:SendCreateTeam(player.rakssid, self.captainUserId)
    end
end

function GameTeam:getCaptainUserId()
    return self.captainUserId
end

function GameTeam:getMembers()
    return self.teamMember
end

function GameTeam:joinTeam(player)
    local captainPlayer = PlayerManager:getPlayerByUserId(self.captainUserId)
    if not captainPlayer then
        return
    end
    table.insert(self.teamMember, tostring(player.userId))
    local title =  player:buildShowName() .. "<" .. captainPlayer.name .. ">"
    player:setShowName(title, 0)
    self:updateCaptainUpArrow()
    GamePacketSender:SendPlayerTeam(player.rakssid, self.captainUserId)
    GamePacketSender:SendMemberUpArrow(player.rakssid, true)
end

function GameTeam:exitTeam(player)
    for pos, memberId in pairs(self.teamMember) do
        if tostring(memberId) == tostring(player.userId) then
            table.remove(self.teamMember, pos)
        end
    end
    player.teamId = ""
    player.joinTime = 0
    player:setShowName(player:buildShowName(), 0)
    GamePacketSender:SendPlayerTeam(player.rakssid, "")
    GamePacketSender:SendMemberUpArrow(player.rakssid, false)
    self:updateCaptainUpArrow()
end

function GameTeam:updateCaptainUpArrow()
    local player = PlayerManager:getPlayerByUserId(self.captainUserId)
    if not player then
        return
    end
    if self:isHaveMember() then
        GamePacketSender:SendCaptainUpArrow(player.rakssid, true)
    else
        GamePacketSender:SendCaptainUpArrow(player.rakssid, false)
    end
end

--解散队伍
function GameTeam:disband()
    for _, userId in pairs(self.teamMember) do
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            player.teamId = ""
            player.joinTime = 0
            player:setShowName(player.name, 0)
            GamePacketSender:SendMemberUpArrow(player.rakssid, false)
        end
    end
    self.teamMember = {}
    self:updateCaptainUpArrow()
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        GamePacketSender:SendDisbandTeam(player.rakssid, self.captainUserId)
    end
end

function GameTeam:isJoinTeam(userId)
    for _, memberId in pairs(self.teamMember) do
        if tostring(memberId) == tostring(userId) then
            return true
        end
    end
    return false
end

--当有人加入算成功
function GameTeam:isHaveMember()
    return #self.teamMember >= 1
end

function GameTeam:copyTeamMember()
    local members = {}
    for _, memberId in pairs(self.teamMember) do
        table.insert(members, memberId)
    end
    return members
end

return GameTeam


